            filename = secure_filename(file.filename or "")
            if "." not in filename:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/new.html", form_data=request.form), 400

            ext = filename.rsplit(".", 1)[1].lower()
            if ext not in allowed_extensions:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/new.html", form_data=request.form), 400

            # Keep backend validation aligned with frontend constraints.
            file.stream.seek(0, os.SEEK_END)
            file_size = file.stream.tell()
            file.stream.seek(0)
            if file_size > 5 * 1024 * 1024:
                flash("图片太大，请压缩后再上传")
                return render_template("posts/new.html", form_data=request.form), 400

            new_filename = secure_filename(f"{uuid4().hex}.{ext}")
            save_path = os.path.join(upload_folder, new_filename)
            file.save(save_path)
            saved_images.append((index, f"/static/uploads/{new_filename}"))

        for index, image_url in saved_images:
            db.session.add(
                PostImage(
                    post_id=post.id,
                    image_url=image_url,
                    sort_order=index,
                )
            )

        db.session.commit()
        flash("帖子发布成功")
        return redirect(url_for("posts.post_detail", post_id=post.id))

    return render_template("posts/new.html", form_data={})


@posts_bp.route("/posts/<int:post_id>/delete", methods=["POST"])
def delete_post(post_id):
    post = Post.query.get_or_404(post_id)
    # TODO: 接入登录系统后，这里需要验证当前用户是否是发帖人

    image_records = post.images.all()
    image_urls = {image.image_url for image in image_records if image.image_url}

    for image_url in image_urls:
        _delete_local_image_file(image_url)

    db.session.delete(post)
    db.session.commit()
    flash("帖子已删除")
    return redirect(url_for("posts.list_posts"))


@posts_bp.route("/posts/<int:post_id>/edit", methods=["GET", "POST"])
def edit_post(post_id):
    post = Post.query.get_or_404(post_id)
    # TODO: 接入登录系统后，这里需要验证当前用户是否是发帖人

    if request.method == "GET":
        return render_template("posts/edit.html", post=post, form_data={})

    title = (request.form.get("title") or "").strip()
    rent = _to_decimal(request.form.get("rent"))
    location = (request.form.get("location") or "").strip()
    uploaded_files = [
        file
        for file in request.files.getlist("images")
        if file and (file.filename or "").strip()
    ]
    delete_image_ids = {
        int(image_id)
        for image_id in request.form.getlist("delete_images")
        if (image_id or "").strip().isdigit()
    }
    allowed_extensions = {"jpg", "jpeg", "png", "webp"}
    existing_images = post.images.all()
    images_by_id = {image.id: image for image in existing_images}
    images_to_delete = [images_by_id[image_id] for image_id in delete_image_ids if image_id in images_by_id]
    remaining_image_count = len(existing_images) - len(images_to_delete)

    if not title or rent is None or not location:
        flash("标题、租金和位置为必填项")
        return render_template("posts/edit.html", post=post, form_data=request.form), 400

    if remaining_image_count + len(uploaded_files) > 6:
        flash("最多上传6张")
        return render_template("posts/edit.html", post=post, form_data=request.form), 400

    post.title = title
    post.rent = rent
    post.location = location
    post.nearby_school = (request.form.get("nearby_school") or "").strip() or None
    post.community_name = (request.form.get("community_name") or "").strip() or None
    post.layout = (request.form.get("layout") or "").strip() or None
    post.area = _to_decimal(request.form.get("area"))
    post.poster_gender = (request.form.get("poster_gender") or "").strip() or None
    post.poster_age = _to_int(request.form.get("poster_age"))
    post.poster_occupation_or_school = (
        (request.form.get("poster_occupation_or_school") or "").strip() or None
    )
    post.poster_intro = (request.form.get("poster_intro") or "").strip() or None
    post.expected_schedule = (request.form.get("expected_schedule") or "").strip() or None
    post.cleaning_frequency = (request.form.get("cleaning_frequency") or "").strip() or None
    post.hobbies = _normalize_hobbies(request.form.get("hobbies", ""))
    post.custom_requirements = (request.form.get("custom_requirements") or "").strip() or None

    for existing_image in images_to_delete:
        _delete_local_image_file(existing_image.image_url)
        db.session.delete(existing_image)

    if uploaded_files:
        upload_folder = current_app.config.get("UPLOAD_FOLDER") or os.path.join(
            current_app.root_path, "static", "uploads"
        )
        os.makedirs(upload_folder, exist_ok=True)

        saved_images = []
        for file in uploaded_files:
            filename = secure_filename(file.filename or "")
            if "." not in filename:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            ext = filename.rsplit(".", 1)[1].lower()
            if ext not in allowed_extensions:
                flash("只接受jpg/jpeg/png/webp格式")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            file.stream.seek(0, os.SEEK_END)
            file_size = file.stream.tell()
            file.stream.seek(0)
            if file_size > 5 * 1024 * 1024:
                flash("图片太大，请压缩后再上传")
                return render_template("posts/edit.html", post=post, form_data=request.form), 400

            new_filename = secure_filename(f"{uuid4().hex}.{ext}")
            save_path = os.path.join(upload_folder, new_filename)
            file.save(save_path)
            saved_images.append(f"/static/uploads/{new_filename}")

        remaining_images = [image for image in existing_images if image not in images_to_delete]
        max_sort_order = max([(image.sort_order or 0) for image in remaining_images], default=-1)

        for offset, image_url in enumerate(saved_images, start=1):
            db.session.add(
                PostImage(
                    post_id=post.id,
                    image_url=image_url,
                    sort_order=max_sort_order + offset,
                )
            )

    db.session.commit()
    flash("帖子更新成功")
    return redirect(url_for("posts.post_detail", post_id=post.id))


@posts_bp.route("/posts/<int:post_id>/favorite", methods=["POST"])
def toggle_favorite(post_id):
    post = Post.query.get_or_404(post_id)
    user_id = _current_user_id()

    favorite = Favorite.query.filter_by(user_id=user_id, post_id=post.id).first()
    if favorite:
        db.session.delete(favorite)
        flash("已取消收藏")
    else:
        db.session.add(Favorite(user_id=user_id, post_id=post.id))
        flash("已加入收藏")

    db.session.commit()
    return redirect(url_for("posts.post_detail", post_id=post.id))


@posts_bp.route("/api/chat", methods=["POST"])
def chat_api():
    payload = request.get_json(silent=True) or {}
    message = (payload.get("message") or "").strip()
    if not message:
        return jsonify({"error": "message不能为空"}), 400

    if OpenAI is None:
        return jsonify({"error": "openai依赖未安装"}), 500

    api_key = (os.getenv("DEEPSEEK_API_KEY") or "").strip()
    if not api_key:
        return jsonify({"error": "DEEPSEEK_API_KEY未配置"}), 500

    posts = Post.query.order_by(Post.created_at.desc()).all()
    listings_context = _build_context_with_limit(posts, MAX_CONTEXT_CHARS)
    if not listings_context:
        listings_context = "当前数据库中暂无房源。"

    user_prompt = (
        "用户需求:\n"
        f"{message}\n\n"
        "房源列表(仅可基于以下内容回答):\n"
        f"{listings_context}"
    )

    try:
        client = OpenAI(base_url=DEEPSEEK_BASE_URL, api_key=api_key)
        completion = client.chat.completions.create(
            model=DEEPSEEK_MODEL,
            messages=[
                {"role": "system", "content": AI_SYSTEM_PROMPT},
                {"role": "user", "content": user_prompt},
            ],
        )
        answer = (completion.choices[0].message.content or "").strip()
        answer_html = _render_chat_answer_html(answer)
    except Exception:
        current_app.logger.exception("DeepSeek chat completion failed")
        return jsonify({"error": "AI服务暂时不可用，请稍后再试"}), 502

    return jsonify({"answer": answer, "answer_html": answer_html})

{% extends "base.html" %}

{% block title %}帖子列表{% endblock %}

{% block content %}
<style>
    .filter-row {
        grid-column: 1 / -1;
        display: flex;
        flex-wrap: wrap;
        align-items: center;
        gap: 8px;
    }
    .rent-tag {
        cursor: pointer;
        padding: 2px 8px;
    }
    .rent-tag.active {
        font-weight: bold;
        text-decoration: underline;
    }
    .rent-input {
        flex: 0 1 5em;
        min-width: 3em;
    }
</style>
<div class="card">
    <form id="filter-form" method="get" action="{{ url_for('posts.list_posts') }}" class="grid grid-2">
        <input type="hidden" id="hidden-min-rent" name="min_rent" value="{{ filters.min_rent }}">
        <input type="hidden" id="hidden-max-rent" name="max_rent" value="{{ filters.max_rent }}">
        <label>位置
            <select name="location">
                <option value="" {% if not filters.location %}selected{% endif %}>不限</option>
                <option value="港岛" {% if filters.location == '港岛' %}selected{% endif %}>港岛</option>
                <option value="九龙" {% if filters.location == '九龙' %}selected{% endif %}>九龙</option>
                <option value="新界" {% if filters.location == '新界' %}selected{% endif %}>新界</option>
                <option value="离岛" {% if filters.location == '离岛' %}selected{% endif %}>离岛</option>
            </select>
        </label>
        <label>附近学校
            <select name="nearby_school">
                <option value="" {% if not filters.nearby_school %}selected{% endif %}>不限</option>
                <option value="HKU" {% if filters.nearby_school == 'HKU' %}selected{% endif %}>香港大学</option>
                <option value="CUHK" {% if filters.nearby_school == 'CUHK' %}selected{% endif %}>香港中文大学</option>
                <option value="HKUST" {% if filters.nearby_school == 'HKUST' %}selected{% endif %}>香港科技大学</option>
                <option value="PolyU" {% if filters.nearby_school == 'PolyU' %}selected{% endif %}>香港理工大学</option>
                <option value="CityU" {% if filters.nearby_school == 'CityU' %}selected{% endif %}>香港城市大学</option>
                <option value="HKBU" {% if filters.nearby_school == 'HKBU' %}selected{% endif %}>香港浸会大学</option>
                <option value="LU" {% if filters.nearby_school == 'LU' %}selected{% endif %}>岭南大学</option>
                <option value="EdUHK" {% if filters.nearby_school == 'EdUHK' %}selected{% endif %}>香港教育大学</option>
            </select>
        </label>
        <div class="filter-row">
            <span>租金</span>
            <button type="button" class="rent-tag {% if filters.min_rent == '' and filters.max_rent == '' %}active{% endif %}" data-min="" data-max="">不限</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '' and filters.max_rent == '3000' %}active{% endif %}" data-min="" data-max="3000">3000以下</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '3000' and filters.max_rent == '5000' %}active{% endif %}" data-min="3000" data-max="5000">3000-5000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '5000' and filters.max_rent == '8000' %}active{% endif %}" data-min="5000" data-max="8000">5000-8000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '8000' and filters.max_rent == '10000' %}active{% endif %}" data-min="8000" data-max="10000">8000-10000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '10000' and filters.max_rent == '15000' %}active{% endif %}" data-min="10000" data-max="15000">10000-15000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '15000' and filters.max_rent == '' %}active{% endif %}" data-min="15000" data-max="">15000以上</button>
            <input id="min-rent" class="rent-input" type="number" step="100" name="custom_min_rent" value="{% if filters.min_rent and (filters.min_rent, filters.max_rent) not in [('', ''), ('', '3000'), ('3000', '5000'), ('5000', '8000'), ('8000', '10000'), ('10000', '15000'), ('15000', '')] %}{{ filters.min_rent }}{% endif %}" placeholder="最低" aria-label="最低租金">
            <span>-</span>
            <input id="max-rent" class="rent-input" type="number" step="100" name="custom_max_rent" value="{% if filters.max_rent and (filters.min_rent, filters.max_rent) not in [('', ''), ('', '3000'), ('3000', '5000'), ('5000', '8000'), ('8000', '10000'), ('10000', '15000'), ('15000', '')] %}{{ filters.max_rent }}{% endif %}" placeholder="最高" aria-label="最高租金">
            <span>元</span>
        </div>
        <label>户型
            <input type="text" name="layout" value="{{ filters.layout }}" placeholder="例如：2室1厅">
        </label>
        <div style="align-self:end;">
            <button class="btn" type="submit">筛选</button>
            <a class="btn secondary inline" href="{{ url_for('posts.new_post') }}">发布新帖子</a>
        </div>
    </form>
</div>

<script>
    (function () {
        var form = document.getElementById("filter-form");
        var hiddenMinInput = document.getElementById("hidden-min-rent");
        var hiddenMaxInput = document.getElementById("hidden-max-rent");
        var minInput = document.getElementById("min-rent");
        var maxInput = document.getElementById("max-rent");
        var tags = document.querySelectorAll(".rent-tag");

        function setActive(target) {
            tags.forEach(function (tag) {
                tag.classList.remove("active");
            });
            if (target) {
                target.classList.add("active");
            }
        }

        tags.forEach(function (tag) {
            tag.addEventListener("click", function () {
                hiddenMinInput.value = tag.getAttribute("data-min") || "";
                hiddenMaxInput.value = tag.getAttribute("data-max") || "";
                minInput.value = "";
                maxInput.value = "";
                setActive(tag);
            });
        });

        function onCustomRentInput() {
            setActive(null);
            hiddenMinInput.value = "";
            hiddenMaxInput.value = "";
        }

        minInput.addEventListener("input", onCustomRentInput);
        maxInput.addEventListener("input", onCustomRentInput);

        form.addEventListener("submit", function () {
            if (minInput.value || maxInput.value) {
                hiddenMinInput.value = minInput.value;
                hiddenMaxInput.value = maxInput.value;
            }
        });

    })();
</script>

{% if posts %}
    <div class="grid grid-2">
        {% for item in posts %}
            <div class="card">
                <a href="{{ url_for('posts.post_detail', post_id=item.post.id) }}">
