        }

        tags.forEach(function (tag) {
            tag.addEventListener("click", function () {
                hiddenMinInput.value = tag.getAttribute("data-min") || "";
                hiddenMaxInput.value = tag.getAttribute("data-max") || "";
                minInput.value = "";
                maxInput.value = "";
                setActive(tag);
            });
        });

        function onCustomRentInput() {
            setActive(null);
            hiddenMinInput.value = "";
            hiddenMaxInput.value = "";
        }

        minInput.addEventListener("input", onCustomRentInput);
        maxInput.addEventListener("input", onCustomRentInput);

        form.addEventListener("submit", function () {
            if (minInput.value || maxInput.value) {
                hiddenMinInput.value = minInput.value;
                hiddenMaxInput.value = maxInput.value;
            }
        });

        function escapeHtml(value) {
            return String(value)
                .replace(/&/g, "&amp;")
                .replace(/</g, "&lt;")
                .replace(/>/g, "&gt;")
                .replace(/\"/g, "&quot;")
                .replace(/'/g, "&#39;");
        }

        function updateAssistantCounter() {
            var value = aiInput.value || "";
            if (value.length > 200) {
                value = value.slice(0, 200);
                aiInput.value = value;
            }
            aiCounter.textContent = "已输入 " + value.length + "/200 字";
        }

        function setAssistantLoading(isLoading) {
            aiSubmit.disabled = isLoading;
            aiSubmit.textContent = isLoading ? "发送中..." : "发送";
        }

        function showAssistantText(content, isError, isHtml) {
            aiResult.hidden = false;
            aiToggle.setAttribute("aria-expanded", "true");
            aiToggle.textContent = "收起回答";
            aiContent.style.display = "block";
            aiContent.classList.toggle("ai-assistant-error", Boolean(isError));
            if (isError) {
                aiContent.innerHTML = "<p>" + escapeHtml(content) + "</p>";
                return;
            }
            aiContent.innerHTML = isHtml ? (content || "") : "<p>" + escapeHtml(content) + "</p>";
        }

        aiToggle.addEventListener("click", function () {
            var expanded = aiToggle.getAttribute("aria-expanded") === "true";
            aiToggle.setAttribute("aria-expanded", String(!expanded));
            aiToggle.textContent = expanded ? "展开回答" : "收起回答";
            aiContent.style.display = expanded ? "none" : "block";
        });

        aiForm.addEventListener("submit", function (event) {
            event.preventDefault();
            var message = (aiInput.value || "").trim();
            if (!message) {
                showAssistantText("请输入找房需求后再发送。", true, false);
                return;
            }

            setAssistantLoading(true);
            fetch("/api/chat", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({ message: message }),
            })
                .then(function (response) {
                    return response.json().then(function (data) {
                        if (!response.ok) {
                            var errorMessage = (data && data.error) || "AI助手暂时不可用，请稍后再试。";
                            throw new Error(errorMessage);
                        }
                        return data;
                    });
                })
                .then(function (data) {
                    showAssistantText((data && data.answer_html) || (data && data.answer) || "没有收到AI回答，请稍后再试。", false, Boolean(data && data.answer_html));
                })
                .catch(function (error) {
                    showAssistantText(error.message || "AI助手暂时不可用，请稍后再试。", true, false);
                })
                .finally(function () {
                    setAssistantLoading(false);
                });
        });

        aiInput.addEventListener("input", updateAssistantCounter);
        updateAssistantCounter();

    })();
</script>

{% if posts %}
    <div class="grid grid-2">
        {% for item in posts %}
            <div class="card">
                <a href="{{ url_for('posts.post_detail', post_id=item.post.id) }}">
                    <img class="list-cover" src="{{ item.cover_url }}" alt="帖子封面">
                </a>
                <h3><a href="{{ url_for('posts.post_detail', post_id=item.post.id) }}">{{ item.post.title }}</a></h3>
                <p>租金：{{ item.post.rent }}</p>
                <p>位置：{{ item.post.location }}</p>
            </div>
        {% endfor %}
    </div>
{% else %}
    <div class="card">暂无帖子</div>
{% endif %}
{% endblock %}

import pytest

from app import app as flask_app
from models import db


@pytest.fixture()
def app():
    flask_app.config.update(
        TESTING=True,
        SQLALCHEMY_DATABASE_URI="sqlite:///:memory:",
        WTF_CSRF_ENABLED=False,
    )

    with flask_app.app_context():
        db.session.remove()
        db.drop_all()
        db.create_all()
        yield flask_app
        db.session.remove()
        db.drop_all()


@pytest.fixture()
def client(app):
    return app.test_client()

from decimal import Decimal
from types import SimpleNamespace

from models import Post, db
from posts import routes


def _create_post(index, intro_text=""):
    post = Post(
        user_id=1,
        title=f"测试房源{index}",
        rent=Decimal("3000.00") + index,
        location="旺角",
        nearby_school="HKU",
        layout="2室1厅",
        poster_intro=intro_text,
    )
    db.session.add(post)
    return post


def test_chat_api_success(client, app, monkeypatch):
    with app.app_context():
        _create_post(1)
        db.session.commit()

    captured = {}

    class FakeCompletions:
        def create(self, **kwargs):
            captured["messages"] = kwargs["messages"]
            return SimpleNamespace(
                choices=[SimpleNamespace(message=SimpleNamespace(content="推荐这套 /posts/1"))]
            )

    class FakeChat:
        def __init__(self):
            self.completions = FakeCompletions()

    class FakeOpenAI:
        def __init__(self, **kwargs):
            self.chat = FakeChat()

    monkeypatch.setenv("DEEPSEEK_API_KEY", "test-key")
    monkeypatch.setattr(routes, "OpenAI", FakeOpenAI)

    response = client.post("/api/chat", json={"message": "我想找3000左右两室"})

    assert response.status_code == 200
    assert response.get_json()["answer"] == "推荐这套 /posts/1"
    assert captured["messages"][1]["role"] == "user"
    assert "/posts/1" in captured["messages"][1]["content"]


def test_chat_api_empty_message_returns_400(client):
    response = client.post("/api/chat", json={"message": "   "})

    assert response.status_code == 400
    assert "error" in response.get_json()


def test_chat_api_provider_failure_returns_502(client, app, monkeypatch):
    with app.app_context():
        _create_post(2)
        db.session.commit()

    class ErrorCompletions:
        def create(self, **kwargs):
            raise RuntimeError("provider unavailable")

    class ErrorChat:
        def __init__(self):
            self.completions = ErrorCompletions()

    class ErrorOpenAI:
        def __init__(self, **kwargs):
            self.chat = ErrorChat()

    monkeypatch.setenv("DEEPSEEK_API_KEY", "test-key")
    monkeypatch.setattr(routes, "OpenAI", ErrorOpenAI)

    response = client.post("/api/chat", json={"message": "帮我推荐"})

    assert response.status_code == 502
    assert "error" in response.get_json()


def test_chat_api_context_is_truncated_when_budget_exceeded(client, app, monkeypatch):
    with app.app_context():
        _create_post(1, intro_text="A" * 220)
        _create_post(2, intro_text="B" * 220)
        _create_post(3, intro_text="C" * 220)
        db.session.commit()

    captured = {}

    class FakeCompletions:
        def create(self, **kwargs):
            captured["user_prompt"] = kwargs["messages"][1]["content"]
            return SimpleNamespace(choices=[SimpleNamespace(message=SimpleNamespace(content="ok"))])

    class FakeChat:
        def __init__(self):
            self.completions = FakeCompletions()

    class FakeOpenAI:
        def __init__(self, **kwargs):
            self.chat = FakeChat()

    monkeypatch.setenv("DEEPSEEK_API_KEY", "test-key")
    monkeypatch.setattr(routes, "OpenAI", FakeOpenAI)
    monkeypatch.setattr(routes, "MAX_CONTEXT_CHARS", 320)

    response = client.post("/api/chat", json={"message": "预算3000"})

    assert response.status_code == 200
    assert "已省略" in captured["user_prompt"]

